function musicPollEsc(s){const d=document.createElement("div");d.textContent=s==null?"":String(s);return d.innerHTML;}
const MUSIC_PLACEHOLDER="data:image/svg+xml,"+
encodeURIComponent('<svg xmlns="http://www.w3.org/2000/svg" width="320" height="320" viewBox="0 0 320 320"><rect fill="#1e293b" width="320" height="320"/><text x="160" y="175" fill="#64748b" font-size="96" text-anchor="middle" font-family="system-ui,sans-serif">♪</text></svg>');const MUSIC_PREVIEW_MAX_MS=30000;function spotifyPreviewPlayUrl(url){if(!url||typeof url!=="string")return"";const u=url.trim();if(!u.startsWith("https://"))return u;try{const h=new URL(u).hostname.toLowerCase();if(h==="p.scdn.co"||h.endsWith(".scdn.co")||h.endsWith(".spotifycdn.com")||h.endsWith(".dzcdn.net")){return`/api/music-poll/preview-audio?url=${encodeURIComponent(u)}`;}}catch(e){}return u;}
let _currentAudio=null;let _currentTrackId=null;let _previewTimer=null;let _pendingPlayTrackId=null;let _playbackGeneration=0;const MUSIC_SWITCH_GAP_MS=140;function clearAllMusicPlaybackUI(){document.querySelectorAll(".music-track-card").forEach((card)=>{card.classList.remove("music-track-card--playing","music-track-card--loading","music-track-card--dimmed");const btn=card.querySelector(".music-track-card__play");if(btn&&!btn.disabled){btn.textContent="▶";btn.setAttribute("aria-label","Écouter un extrait");}});}
function setTrackPlayingUI(trackId,state){document.querySelectorAll(".music-track-card").forEach((card)=>{const isThis=card.dataset.trackId===String(trackId);card.classList.toggle("music-track-card--playing",isThis&&state==="playing");card.classList.toggle("music-track-card--loading",isThis&&state==="loading");card.classList.toggle("music-track-card--dimmed",!isThis&&(state==="playing"||state==="loading"));const btn=card.querySelector(".music-track-card__play");if(!btn||btn.disabled||!isThis)return;if(state==="playing"){btn.textContent="⏸";btn.setAttribute("aria-label","Arrêter l’extrait");}else if(state==="loading"){btn.textContent="⏳";btn.setAttribute("aria-label","Chargement de l’extrait");}else{btn.textContent="▶";btn.setAttribute("aria-label","Écouter un extrait");}});}
function playPreview(previewUrl,trackId){stopPreview();_pendingPlayTrackId=trackId;const gen=_playbackGeneration;setTimeout(()=>{if(gen!==_playbackGeneration)return;setTrackPlayingUI(trackId,"loading");const audio=new Audio();audio.src=previewUrl;audio.volume=0.8;_currentAudio=audio;_currentTrackId=trackId;_pendingPlayTrackId=null;audio.addEventListener("playing",()=>{if(gen!==_playbackGeneration)return;setTrackPlayingUI(trackId,"playing");});audio.addEventListener("ended",()=>{if(gen!==_playbackGeneration)return;stopPreview();});audio.addEventListener("error",()=>{if(gen!==_playbackGeneration)return;stopPreview();});audio.play().catch(()=>{if(gen!==_playbackGeneration)return;stopPreview();});_previewTimer=setTimeout(()=>{if(gen!==_playbackGeneration)return;stopPreview();},MUSIC_PREVIEW_MAX_MS);},MUSIC_SWITCH_GAP_MS);}
function stopPreview(){_playbackGeneration+=1;clearTimeout(_previewTimer);_previewTimer=null;if(_currentAudio){try{_currentAudio.pause();_currentAudio.src="";_currentAudio.removeAttribute("src");}catch(e){}
_currentAudio=null;}
_currentTrackId=null;_pendingPlayTrackId=null;clearAllMusicPlaybackUI();}
function stopAllPreviews(){stopPreview();}
function onTrackPlayClick(card){const trackId=card.dataset.trackId;const previewUrl=card.dataset.previewUrl;if(!previewUrl)return;const same=String(trackId);if(String(_currentTrackId)===same&&_currentAudio){stopPreview();return;}
if(String(_pendingPlayTrackId)===same){stopPreview();return;}
playPreview(previewUrl,trackId);}
function hideMusicPollModule(){document.getElementById("music-poll-modules-host")?.remove();document.querySelectorAll('[id^="music-poll-module"]').forEach((el)=>el.remove());}
function buildMusicPollDOM(poll){const section=document.createElement("section");section.id=`music-poll-module-${poll.id}`;section.className="music-poll";section.dataset.pollId=String(poll.id);const pl=poll.spotify_playlist_url?`<a class="music-poll__playlist-btn" href="${musicPollEsc(
              poll.spotify_playlist_url
          )}" target="_blank" rel="noopener">Toute la playlist ↗</a>`:"";const cards=poll.tracks.map((t)=>{const thumb=t.thumbnail_url||MUSIC_PLACEHOLDER;const prevAvail=t.preview_available&&t.preview_url;const playCls=prevAvail?"music-track-card__play":"music-track-card__play music-track-card__play--disabled";const disabledAttr=prevAvail?"":" disabled";const noPrev=prevAvail?"":'<div class="music-track-card__no-preview">Aperçu indisponible</div>';const votedCls=t.has_voted?" music-track-card--voted":"";const voteActive=t.has_voted?" music-track-card__vote--active":"";const heart=t.has_voted?"♥":"♡";return`
<div class="music-track-card${votedCls}"
     data-track-id="${t.id}"
     data-has-voted="${t.has_voted ? "true" : "false"}"
     data-preview-url="${musicPollEsc(spotifyPreviewPlayUrl(t.preview_url || ""))}"
     data-spotify-url="${musicPollEsc(t.spotify_url)}">
  <div class="music-track-card__cover">
    <img src="${musicPollEsc(thumb)}" alt="${musicPollEsc(t.title)}" loading="lazy" width="180" height="180">
    <div class="music-track-card__play-overlay">
      <button type="button" class="${playCls}"${disabledAttr} aria-label="Écouter un extrait">▶</button>
    </div>
  </div>
  <div class="music-track-card__info">
    <div class="music-track-card__title">${musicPollEsc(t.title)}</div>
    <div class="music-track-card__artist">${musicPollEsc(t.artist)}</div>
    ${noPrev}
  </div>
  <div class="music-track-card__actions">
    <button type="button" class="music-track-card__vote${voteActive}">
      <span class="vote-icon">${heart}</span>
      <span class="music-track-card__count">${t.vote_count}</span>
    </button>
    <a class="music-track-card__listen" href="${musicPollEsc(t.spotify_url)}" target="_blank" rel="noopener">Écouter ↗</a>
  </div>
</div>`;}).join("");section.innerHTML=`
<div class="music-poll__header">
  <span class="music-poll__icon" aria-hidden="true">🎵</span>
  <div>
    <h2 class="music-poll__title">${musicPollEsc(poll.title)}</h2>
    <span class="music-poll__subtitle">Vote pour ta musique préférée</span>
  </div>
  ${pl}
</div>
<div class="music-poll__tracks">${cards}</div>`;return section;}
function renderMusicPollModule(data){const poll=data.poll;if(!poll||data.active===false){hideMusicPollModule();stopAllPreviews();return;}
const anchor=document.getElementById("suggestions-list");if(!anchor)return;const sig=`${poll.id}|${poll.title || ""}|${poll.spotify_playlist_url || ""}|${(poll.tracks || []).map((t) => t.id).join(",")}`;const existing=document.getElementById(`music-poll-module-${poll.id}`);if(existing&&existing.dataset.renderSig===sig){existing.dataset.sessionVotes=String(poll.session_votes_count);poll.tracks.forEach((track)=>{const card=existing.querySelector(`[data-track-id="${track.id}"]`);if(!card)return;card.dataset.hasVoted=track.has_voted?"true":"false";card.dataset.previewUrl=spotifyPreviewPlayUrl(track.preview_url||"");card.classList.toggle("music-track-card--voted",track.has_voted);const voteBtn=card.querySelector(".music-track-card__vote");if(voteBtn){voteBtn.classList.toggle("music-track-card__vote--active",track.has_voted);const countEl=voteBtn.querySelector(".music-track-card__count");if(countEl)countEl.textContent=track.vote_count;const icon=voteBtn.querySelector(".vote-icon");if(icon)icon.textContent=track.has_voted?"♥":"♡";}});return;}
document.getElementById("music-poll-modules-host")?.remove();hideMusicPollModule();const el=buildMusicPollDOM(poll);el.dataset.renderSig=sig;el.dataset.sessionVotes=String(poll.session_votes_count);el.dataset.pollId=String(poll.id);el.dataset.maxVotes=String(poll.max_votes);bindMusicPollEvents(el);anchor.parentNode.insertBefore(el,anchor);}
function applyOptimisticMusicVote(card,removeVote){const btn=card.querySelector(".music-track-card__vote");const countEl=card.querySelector(".music-track-card__count");const count=parseInt(countEl?.textContent||"0",10);card.dataset.hasVoted=removeVote?"false":"true";card.classList.toggle("music-track-card--voted",!removeVote);btn?.classList.toggle("music-track-card__vote--active",!removeVote);const icon=btn?.querySelector(".vote-icon");if(icon)icon.textContent=removeVote?"♡":"♥";if(countEl)countEl.textContent=String(removeVote?Math.max(0,count-1):count+1);}
function applyCanonicalMusicVote(card,data){card.dataset.hasVoted=data.has_voted?"true":"false";card.classList.toggle("music-track-card--voted",data.has_voted);const btn=card.querySelector(".music-track-card__vote");btn?.classList.toggle("music-track-card__vote--active",data.has_voted);const icon=btn?.querySelector(".vote-icon");if(icon)icon.textContent=data.has_voted?"♥":"♡";const countEl=card.querySelector(".music-track-card__count");if(countEl)countEl.textContent=data.vote_count;}
async function onTrackVoteClick(card,root){const pollId=parseInt(root.dataset.pollId||"0",10);const maxVotes=parseInt(root.dataset.maxVotes||"1",10);let currentSessionVotes=parseInt(root.dataset.sessionVotes||"0",10);const trackId=parseInt(card.dataset.trackId||"0",10);const hasVoted=card.dataset.hasVoted==="true";const removeVote=hasVoted;if(!removeVote&&currentSessionVotes>=maxVotes){if(typeof showFeedback==="function"){showFeedback(`Tu as déjà voté pour ${maxVotes} morceau${maxVotes > 1 ? "x" : ""}`,"warning");}
return;}
applyOptimisticMusicVote(card,removeVote);if(!removeVote)root.dataset.sessionVotes=String(currentSessionVotes+1);else root.dataset.sessionVotes=String(Math.max(0,currentSessionVotes-1));try{const r=await fetch(`/api/music-poll/${pollId}/vote`,{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json"},body:JSON.stringify({track_id:trackId,remove_vote:removeVote}),});const data=await r.json();if(!r.ok){applyOptimisticMusicVote(card,!removeVote);root.dataset.sessionVotes=String(currentSessionVotes);if(data.message&&typeof showFeedback==="function")showFeedback(data.message,"warning");return;}
applyCanonicalMusicVote(card,data);root.dataset.sessionVotes=String(data.session_votes_count);}catch(e){applyOptimisticMusicVote(card,!removeVote);root.dataset.sessionVotes=String(currentSessionVotes);}}
function bindMusicPollEvents(root){root.addEventListener("click",(e)=>{const t=e.target;const playBtn=t.closest&&t.closest(".music-track-card__play");if(playBtn&&root.contains(playBtn)){if(playBtn.disabled)return;e.preventDefault();const card=playBtn.closest(".music-track-card");if(card)onTrackPlayClick(card);return;}
const voteBtn=t.closest&&t.closest(".music-track-card__vote");if(voteBtn&&root.contains(voteBtn)){e.preventDefault();const card=voteBtn.closest(".music-track-card");if(card)onTrackVoteClick(card,root);}});}
function bindMusicPollPreviewEvents(root){root.addEventListener("click",(e)=>{const playBtn=e.target.closest&&e.target.closest(".music-track-card__play");if(playBtn&&root.contains(playBtn)){if(playBtn.disabled)return;e.preventDefault();const card=playBtn.closest(".music-track-card");if(card)onTrackPlayClick(card);return;}
const voteBtn=e.target.closest&&e.target.closest(".music-track-card__vote");if(voteBtn&&root.contains(voteBtn)){e.preventDefault();}});}
async function pollMusicPoll(){try{const data=await fetch("/api/music-poll/active",{credentials:"same-origin"}).then((r)=>r.json());if(!data.active){hideMusicPollModule();stopAllPreviews();return;}
renderMusicPollModule(data);}catch(e){}}
function initMusicPollModule(){pollMusicPoll();setInterval(pollMusicPoll,30000);}
window.MusicPollWidget={buildDOM:buildMusicPollDOM,bindPreview:bindMusicPollPreviewEvents,stopAll:stopAllPreviews,};